function SearchBox() {
  // BUG: no ref is created, so the button has no way to focus the input
  return (
    <div style={{ padding: '40px', fontFamily: 'sans-serif', color: '#e0e0e0', background: '#16213e', borderRadius: '8px', maxWidth: '420px', margin: '40px auto' }}>
      <h2 style={{ marginTop: 0 }}>Search</h2>
      <input placeholder="Type here" style={{ padding: '8px', width: '100%', boxSizing: 'border-box', marginBottom: '12px' }} />
      <button onClick={() => {}} style={{ padding: '8px 16px', background: '#e94560', color: '#fff', border: 'none', borderRadius: '4px', cursor: 'pointer' }}>
        Focus the input
      </button>
    </div>
  );
}
